from collections import deque

def sliding_window_max(nums, k):
    """Return maximums for each contiguous subarray of length k."""
    if k > len(nums):
        return []

    q = deque()
    res = []

    for i, num in enumerate(nums):
        while q and nums[q[-1]] <= num:
            q.pop()
        q.append(i)
        if q[0] <= i - k:
            q.popleft()
        if i >= k - 1:
            res.append(nums[q[0]])

    return res
```

from datetime import date, timedelta

def next_occurrence_of_weekday(date_str: str, weekday_name: str) -> str:
    """Return the next date strictly after date_str matching weekday_name."""
    weekdays = {
        'Monday': 0, 'Tuesday': 1, 'Wednesday': 2, 'Thursday': 3,
        'Friday': 4, 'Saturday': 5, 'Sunday': 6
    }
    d = date.fromisoformat(date_str)
    target = weekdays[weekday_name]
