def candy_distribution(ratings):
    """Return minimum candies so each child gets at least 1 and higher-rated
    children receive more than their immediate neighbors."""
    n = len(ratings)
    if n == 0:
        return 0
    candies = [1] * n
    for i in range(1, n):
        if ratings[i] > ratings[i - 1]:
            candies[i] = candies[i - 1] + 1
    for i in range(n - 2, -1, -1):
